-0.795,-0.459,55.0,33.0)\"><path d=\"M -3 3 L -3 -15 A 18 18 0 0 1 15 3 Z\" fill=\"#ffffff\" stroke=\"#111111\" stroke-width=\"2.5\"/></g></svg>", "<svg xmlns=\"http://www.w3.org/2000/svg\" viewBox=\"0 0 110 116\" width=\"104\" height=\"109\" role=\"img\"><rect x=\"0\" y=\"0\" width=\"110\" height=\"116\" fill=\"#ffffff\"/><polygon points=\"8.2,87.0 55.0,114.0 55.0,60.0 8.2,33.0\" fill=\"#ffffff\" stroke=\"#111111\" stroke-width=\"2\"/><g transform=\"matrix(0.000,-0.918,0.795,0.459,31.6,73.5)\"><circle cx=\"0\" cy=\"0\" r=\"12\" fill=\"#ffffff\" stroke=\"#111111\" stroke-width=\"3.5\"/></g><polygon points=\"101.8,87.0 55.0,114.0 55.0,60.0 101.8,33.0\" fill=\"#ffffff\" stroke=\"#111111\" stroke-width=\"2\"/><g transform=\"matrix(0.795,-0.459,-0.000,0.918,78.4,73.5)\"><path d=\"M -3 3 L -3 -15 A 18 18 0 0 1 15 3 Z\" fill=\"#ffffff\" stroke=\"#111111\" stroke-width=\"2.5\"/></g><polygon points=\"55.0,6.0 101.8,33.0 55.0,60.0 8.2,33.0\" fill=\"#ffffff\" stroke=\"#111111\" stroke-width=\"2\"/><g transform=\"matrix(0.795,-0.459,0.795,0.459,55.0,33.0)\"><line x1=\"-2\" y1=\"-17\" x2=\"-2\" y2=\"17\" stroke=\"#111111\" stroke-width=\"3\"/><polygon points=\"-2,-17 16,-9 -2,-1\" fill=\"#111111\" stroke=\"#111111\" stroke-width=\"2\"/></g></svg>", "<svg xmlns=\"http://www.w3.org/2000/svg\" viewBox=\"0 0 110 116\" width=\"104\" height=\"109\" role=\"img\"><rect x=\"0\" y=\"0\" width=\"110\" height=\"116\" fill=\"#ffffff\"/><polygon points=\"8.2,87.0 55.0,114.0 55.0,60.0 8.2,33.0\" fill=\"#ffffff\" stroke=\"#111111\" stroke-width=\"2\"/><g transform=\"matrix(0.795,0.459,-0.000,0.918,31.6,73.5)\"><polygon points=\"-12,-17 -4,-17 -4,9 14,9 14,17 -12,17\" fill=\"#ffffff\" stroke=\"#111111\" stroke-width=\"2.5\"/></g><polygon points=\"101.8,87.0 55.0,114.0 55.0,60.0 101.8,33.0\" fill=\"#ffffff\" stroke=\"#111111\" stroke-width=\"2\"/><g transform=\"matrix(-0.795,0.459,-0.000,-0.918,78.4,73.5)\"><polygon points=\"0,-17 13,1 6,1 6,17 -6,17 -6,1 -13,1\" fill=\"#111111\" stroke=\"#111111\" stroke-width=\"2.5\"/></g><polygon points=\"55.0,6.0 101.8,33.0 55.0,60.0 8.2,33.0\" fill=\"#ffffff\" stroke=\"#111111\" stroke-width=\"2\"/><g transform=\"matrix(0.795,0.459,-0.795,0.459,55.0,33.0)\"><line x1=\"-2\" y1=\"-17\" x2=\"-2\" y2=\"17\" stroke=\"#111111\" stroke-width=\"3\"/><polygon points=\"-2,-17 16,-9 -2,-1\" fill=\"#111111\" stroke=\"#111111\" stroke-width=\"2\"/></g></svg>"]', 1, 'Check each cube against the net using duds, opposite faces and orientation. one option shows the flag next to the L-shape, but they are on opposite faces of the net; one option the arrow is rotated the wrong way; one option the ring is the wrong colour. The remaining cube is consistent with the net.', false),
  (103, 2, 'Each figure is labelled with its code. Work out what each letter stands for, then select the code for the final figure.
<svg xmlns="http://www.w3.org/2000/svg" viewBox="0 0 720 146" width="720" height="146" role="img"><rect x="0" y="0" width="720" height="146" fill="#ffffff"/><g transform="translate(54,56)"><rect x="-50" y="-50" width="100" height="100" fill="#ffffff" stroke="#111111" stroke-width="2"/><g transform="translate(0,-6)"><polygon points="0,-22 22,19 -22,19" fill="#ffffff" stroke="#111111" stroke-width="2.5"/></g><g transform="translate(0,4)"><circle cx="0" cy="0" r="8" fill="none" stroke="#111111" stroke-width="3.5"/></g><circle cx="0" cy="41" r="5" fill="#111111"/></g><text x="54" y="132" text-anchor="middle" font-family="sans-serif" font-size="16" font-weight="bold" fill="#111111">B Z F</text><g transform="translate(166,56)"><rect x="-50" y="-50" width="100" height="100" fill="#ffffff" stroke="#111111" stroke-width="2"/><g transform="translate(0,0)"><circle cx="0" cy="0" r="33" fill="#111111" stroke="#111111" stroke-width="2.5"/></g><g transform="translate(0,0)"><polygon points="-3,-11 3,-11 3,-3 11,-3 11,3 3,3 3,11 -3,11 -3,3 -11,3 -11,-3 -3,-3" fill="#ffffff"/></g><circle cx="0" cy="41" r="5" fill="#111111"/></g><text x="166" y="132" text-anchor="middle" font-family="sans-serif" font-size="16" font-weight="bold" fill="#111111">A Z G</text><g transform="translate(278,56)"><rect x="-50" y="-50" width="100" height="100" fill="#ffffff" stroke="#111111" stroke-width="2"/><g transform="translate(0,0)"><circle cx="0" cy="0" r="22" fill="#bbbbbb" stroke="#111111" stroke-width="2.5"/></g><g transform="translate(0,0)"><polygon points="-3,-11 3,-11 3,-3 11,-3 11,3 3,3 3,11 -3,11 -3,3 -11,3 -11,-3 -3,-3" fill="#111111"/></g><circle cx="0" cy="-41" r="5" fill="#111111"/></g><text x="278" y="132" text-anchor="middle" font-family="sans-serif" font-size="16" font-weight="bold" fill="#111111">A X G</text><g transform="translate(390,56)"><rect x="-50" y="-50" width="100" height="100" fill="#ffffff" stroke="#111111" stroke-width="2"/><g transform="translate(0,0)"><circle cx="0" cy="0" r="22" fill="#bbbbbb" stroke="#111111" stroke-width="2.5"/></g><g transform="translate(0,0)"><circle cx="0" cy="0" r="8" fill="none" stroke="#111111" stroke-width="3.5"/></g><circle cx="0" cy="41" r="5" fill="#111111"/></g><text x="390" y="132" text-anchor="middle" font-family="sans-serif" font-size="16" font-weight="bold" fill="#111111">B Z G</text><g transform="translate(502,56)"><rect x="-50" y="-50" width="100" height="100" fill="#ffffff" stroke="#111111" stroke-width="2"/><g transform="translate(0,-6)"><polygon points="0,-22 22,19 -22,19" fill="#bbbbbb" stroke="#111111" stroke-width="2.5"/></g><g transform="translate(0,4)"><polygon points="0,-10 10,0 0,10 -10,0" fill="#111111"/></g><circle cx="41" cy="0" r="5" fill="#111111"/></g><text x="502" y="132" text-anchor="middle" font-family="sans-serif" font-size="16" font-weight="bold" fill="#111111">C Y F</text><g transform="translate(650,56)"><rect x="-50" y="-50" width="100" height="100" fill="#ffffff" stroke="#111111" stroke-width="2"/><g transform="translate(0,-6)"><polygon points="0,-33 33,28 -33,28" fill="#bbbbbb" stroke="#111111" stroke-width="2.5"/></g><g transform="translate(0,4)"><polygon points="0,-10 10,0 0,10 -10,0" fill="#111111"/></g><circle cx="41" cy="0" r="5" fill="#111111"/></g><text x="650" y="132" text-anchor="middle" font-family="sans-serif" font-size="20" font-weight="bold" fill="#111111">?</text></svg>', '["C Z F", "C Y F", "C X F", "C Y G"]', 1, 'First letter codes the inner mark (A = cross, B = ring, C = diamond); Second letter codes the dot position (X = N, Y = E, Z = S); Third letter codes the outer shape (G = circle, F = triangle). The final figure''s code is C Y F.', false),
  (104, 2, 'Three of these figures are rotations of one figure. Select the one that is most unlike the others.', '["<svg xmlns=\"http://www.w3.org/2000/svg\" viewBox=\"0 0 110 110\" width=\"104\" height=\"104\" role=\"img\"><rect x=\"0\" y=\"0\" width=\"110\" height=\"110\" fill=\"#ffffff\"/><rect x=\"3\" y=\"3\" width=\"104\" height=\"104\" fill=\"#ffffff\" stroke=\"#111111\" stroke-width=\"2\"/><g transform=\"translate(55,55) rotate(315) scale(0.85)\"><g transform=\"translate(0,16) rotate(0) scale(1.6)\"><circle cx=\"0\" cy=\"0\" r=\"15\" fill=\"#ffffff\" stroke=\"#111111\" stroke-width=\"2.5\"/><path d=\"M -15 0 A 15 15 0 0 1 15 0 Z\" fill=\"#111111\" stroke=\"#111111\" stroke-width=\"2.5\"/></g><g transform=\"translate(28,-20) rotate(0) scale(0.7)\"><line x1=\"-2\" y1=\"-17\" x2=\"-2\" y2=\"17\" stroke=\"#111111\" stroke-width=\"3\"/><polygon points=\"-2,-17 16,-9 -2,-1\" fill=\"#ffffff\" stroke=\"#111111\" stroke-width=\"2\"/></g><rect x=\"-38\" y=\"-30\" width=\"16\" height=\"16\" fill=\"#ffffff\" stroke=\"#111111\" stroke-width=\"2\"/></g></svg>", "<svg xmlns=\"http://www.w3.org/2000/svg\" viewBox=\"0 0 110 110\" width=\"104\" height=\"104\" role=\"img\"><rect x=\"0\" y=\"0\" width=\"110\" height=\"110\" fill=\"#ffffff\"/><rect x=\"3\" y=\"3\" width=\"104\" height=\"104\" fill=\"#ffffff\" stroke=\"#111111\" stroke-width=\"2\"/><g transform=\"translate(55,55) rotate(180) scale(0.85)\"><g transform=\"translate(0,16) rotate(0) scale(1.6)\"><circle cx=\"0\" cy=\"0\" r=\"15\" fill=\"#ffffff\" stroke=\"#111111\" stroke-width=\"2.5\"/><path d=\"M -15 0 A 15 15 0 0 1 15 0 Z\" fill=\"#111111\" stroke=\"#111111\" stroke-width=\"2.5\"/></g><g transform=\"translate(28,-20) rotate(0) scale(0.7)\"><line x1=\"-2\" y1=\"-17\" x2=\"-2\" y2=\"17\" stroke=\"#111111\" stroke-width=\"3\"/><polygon points=\"-2,-17 16,-9 -2,-1\" fill=\"#ffffff\" stroke=\"#111111\" stroke-width=\"2\"/></g><rect x=\"-38\" y=\"-30\" width=\"16\" height=\"16\" fill=\"#bbbbbb\" stroke=\"#111111\" stroke-width=\"2\"/></g></svg>", "<svg xmlns=\"http://www.w3.org/2000/svg\" viewBox=\"0 0 110 110\" width=\"104\" height=\"104\" role=\"img\"><rect x=\"0\" y=\"0\" width=\"110\" height=\"110\" fill=\"#ffffff\"/><rect x=\"3\" y=\"3\" width=\"104\" height=\"104\" fill=\"#ffffff\" stroke=\"#111111\" stroke-width=\"2\"/><g transform=\"translate(55,55) rotate(90) scale(0.85)\"><g transform=\"translate(0,16) rotate(0) scale(1.6)\"><circle cx=\"0\" cy=\"0\" r=\"15\" fill=\"#ffffff\" stroke=\"#111111\" stroke-width=\"2.5\"/><path d=\"M -15 0 A 15 15 0 0 1 15 0 Z\" fill=\"#111111\" stroke=\"#111111\" stroke-width=\"2.5\"/></g><g transform=\"translate(28,-20) rotate(0) scale(0.7)\"><line x1=\"-2\" y1=\"-17\" x2=\"-2\" y2=\"17\" stroke=\"#111111\" stroke-width=\"3\"/><polygon points=\"-2,-17 16,-9 -2,-1\" fill=\"#ffffff\" stroke=\"#111111\" stroke-width=\"2\"/></g><rect x=\"-38\" y=\"-30\" width=\"16\" height=\"16\" fill=\"#ffffff\" stroke=\"#111111\" stroke-width=\"2\"/></g></svg>", "<svg xmlns=\"http://www.w3.org/2000/svg\" viewBox=\"0 0 110 110\" width=\"104\" height=\"104\" role=\"img\"><rect x=\"0\" y=\"0\" width=\"110\" height=\"110\" fill=\"#ffffff\"/><rect x=\"3\" y=\"3\" width=\"104\" height=\"104\" fill=\"#ffffff\" stroke=\"#111111\" stroke-width=\"2\"/><g transform=\"translate(55,55) rotate(135) scale(-1,1) scale(0.85)\"><g transform=\"translate(0,16) rotate(0) scale(1.6)\"><circle cx=\"0\" cy=\"0\" r=\"15\" fill=\"#ffffff\" stroke=\"#111111\" stroke-width=\"2.5\"/><path d=\"M -15 0 A 15 15 0 0 1 15 0 Z\" fill=\"#111111\" stroke=\"#111111\" stroke-width=\"2.5\"/></g><g transform=\"translate(28,-20) rotate(0) scale(0.7)\"><line x1=\"-2\" y1=\"-17\" x2=\"-2\" y2=\"17\" stroke=\"#111111\" stroke-width=\"3\"/><polygon points=\"-2,-17 16,-9 -2,-1\" fill=\"#ffffff\" stroke=\"#111111\" stroke-width=\"2\"/></g><rect x=\"-38\" y=\"-30\" width=\"16\" height=\"16\" fill=\"#bbbbbb\" stroke=\"#111111\" stroke-width=\"2\"/></g></svg>"]', 3, 'The odd one out is a REFLECTION of the others, not a rotation - check which side of the half-shaded circle the flag sits on as you rotate each figure. The shading differences are a red herring - no single figure is uniquely shaded.', false),
  (105, 2, 'Each figure is labelled with its code. Work out what each letter stands for, then select the code for the final figure.
